#include <stdio.h>
#include <stdlib.h>
#include <string.h>

#define RECORD_SIZE 50
#define MAX_RECORDS 100

// Structure for ISAM index entry
typedef struct {
 char key[10];
 long position; // File position pointer
} IndexEntry;

// ==================== SEQUENTIAL ACCESS ====================
void sequentialWrite(const char *filename, char records[][RECORD_SIZE], int count) {
 FILE *fp = fopen(filename, "wb");
 if (!fp) {
 printf("Error opening file for sequential write\n");
 return;
 }

 for (int i = 0; i < count; i++) {
 // Pad record to fixed size
 char padded[RECORD_SIZE];
 memset(padded, ' ', RECORD_SIZE);
 strncpy(padded, records[i], strlen(records[i]));
 fwrite(padded, 1, RECORD_SIZE, fp);
 }

 fclose(fp);
 printf("[SEQUENTIAL] Wrote %d records\n", count);
}

void sequentialRead(const char *filename) {
 FILE *fp = fopen(filename, "rb");
 if (!fp) {
 printf("Error opening file for sequential read\n");
 return;
 }

 char buffer[RECORD_SIZE];
 int record_num = 0;

 // Read from beginning, one record at a time
 while (fread(buffer, 1, RECORD_SIZE, fp) == RECORD_SIZE) {
 // Trim whitespace
 buffer[RECORD_SIZE - 1] = '\0';
 printf("Record %d: %s\n", record_num++, buffer);
 }

 fclose(fp);
}

// ==================== DIRECT ACCESS ====================
void directRead(const char *filename, int recordNumber) {
 FILE *fp = fopen(filename, "rb");
 if (!fp) {
 printf("Error opening file for direct read\n");
 return;
 }

 // Calculate byte position: record_number * size_of_each_record
 long position = (long)recordNumber * RECORD_SIZE;

 // Seek directly to that position
 fseek(fp, position, SEEK_SET);

 char buffer[RECORD_SIZE];
 if (fread(buffer, 1, RECORD_SIZE, fp) == RECORD_SIZE) {
 buffer[RECORD_SIZE - 1] = '\0';
 printf("[DIRECT] Record %d: %s\n", recordNumber, buffer);
 } else {
 printf("[DIRECT] Record %d not found\n", recordNumber);
 }

 fclose(fp);
}

void directWrite(const char *filename, int recordNumber, const char *data) {
 FILE *fp = fopen(filename, "r+b"); // Open for read/write binary
 if (!fp) {
 printf("Error opening file for direct write\n");
 return;
 }

 long position = (long)recordNumber * RECORD_SIZE;
 fseek(fp, position, SEEK_SET);

 char padded[RECORD_SIZE];
 memset(padded, ' ', RECORD_SIZE);
 strncpy(padded, data, strlen(data));

 fwrite(padded, 1, RECORD_SIZE, fp);
 printf("[DIRECT] Wrote to record %d\n", recordNumber);

 fclose(fp);
}

// ==================== INDEXED SEQUENTIAL ACCESS (ISAM) ====================
void isamCreateIndex(const char *dataFile, const char *indexFile) {
 FILE *dataFp = fopen(dataFile, "rb");
 if (!dataFp) {
 printf("Error opening data file\n");
 return;
 }

 IndexEntry index[MAX_RECORDS];
 int indexCount = 0;

 // Scan data file sequentially to build index
 char buffer[RECORD_SIZE];
 long position = 0;

 while (fread(buffer, 1, RECORD_SIZE, dataFp) == RECORD_SIZE) {
 // Extract key (first field before comma)
 char key[10];
 int i = 0;
 while (buffer[i] != ',' && i < 9) {
 key[i] = buffer[i];
 i++;
 }
 key[i] = '\0';

 // Store in index
 strcpy(index[indexCount].key, key);
 index[indexCount].position = position;
 indexCount++;

 position = ftell(dataFp); // Get current position
 }
 fclose(dataFp);

 // Sort index by key (bubble sort for simplicity)
 for (int i = 0; i < indexCount - 1; i++) {
 for (int j = 0; j < indexCount - i - 1; j++) {
 if (strcmp(index[j].key, index[j + 1].key) > 0) {
 IndexEntry temp = index[j];
 index[j] = index[j + 1];
 index[j + 1] = temp;
 }
 }
 }

 // Write index to file
 FILE *idxFp = fopen(indexFile, "wb");
 fwrite(index, sizeof(IndexEntry), indexCount, idxFp);
 fclose(idxFp);

 printf("[ISAM] Created index with %d entries\n", indexCount);
}

char* isamSearch(const char *dataFile, const char *indexFile, const char *searchKey) {
 FILE *idxFp = fopen(indexFile, "rb");
 if (!idxFp) {
 printf("[ISAM] Index not found\n");
 return NULL;
 }

 // Load index into memory
 IndexEntry index[MAX_RECORDS];
 int count = fread(index, sizeof(IndexEntry), MAX_RECORDS, idxFp);
 fclose(idxFp);

 // Binary search on index
 int left = 0, right = count - 1;
 int found = 0;
 long targetPosition = -1;

 while (left <= right) {
 int mid = (left + right) / 2;
 int cmp = strcmp(index[mid].key, searchKey);

 if (cmp == 0) {
 targetPosition = index[mid].position;
 found = 1;
 break;
 } else if (cmp < 0) {
 left = mid + 1;
 } else {
 right = mid - 1;
 }
 }

 if (!found) {
 printf("[ISAM] Key '%s' not found\n", searchKey);
 return NULL;
 }

 // Direct access to data file using position from index
 FILE *dataFp = fopen(dataFile, "rb");
 fseek(dataFp, targetPosition, SEEK_SET);

 static char result[RECORD_SIZE];
 fread(result, 1, RECORD_SIZE, dataFp);
 result[RECORD_SIZE - 1] = '\0';
 fclose(dataFp);

 return result;
}

// ==================== MAIN DEMONSTRATION ====================
int main() {
 const char *dataFile = "students.dat";
 const char *indexFile = "students.idx";

 // Sample student records: ID,Name,Grade
 char records[5][RECORD_SIZE] = {
 "101,Alice,A",
 "102,Bob,B",
 "103,Charlie,A",
 "104,Diana,C",
 "105,Eve,B"
 };

 printf("========================================\n");
 printf("1. SEQUENTIAL ACCESS DEMONSTRATION\n");
 printf("========================================\n");
 sequentialWrite(dataFile, records, 5);
 printf("Reading all records sequentially:\n");
 sequentialRead(dataFile);

 printf("\n========================================\n");
 printf("2. DIRECT ACCESS DEMONSTRATION\n");
 printf("========================================\n");
 directRead(dataFile, 2); // Read 3rd record directly
 directWrite(dataFile, 2, "103,Modified,A");
 directRead(dataFile, 2);

 printf("\n========================================\n");
 printf("3. ISAM ACCESS DEMONSTRATION\n");
 printf("========================================\n");
 isamCreateIndex(dataFile, indexFile);

 char *result = isamSearch(dataFile, indexFile, "103");
 if (result) printf("ISAM search for '103': %s\n", result);

 result = isamSearch(dataFile, indexFile, "105");
 if (result) printf("ISAM search for '105': %s\n", result);

 result = isamSearch(dataFile, indexFile, "999");
 if (!result) printf("ISAM search for '999': Not found\n");

 return 0;
}
